  ('aboriginal-c5fb3965-moex-00051', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲男與乙女為夫妻共同收養一未成年人，並經法院裁定認可。數年之後，被收養者已成年，甲男與乙女認 無繼續收養之必要，經法院裁定終止收養關係，對於向戶政事務所申辦收養及終止收養登記時，有關申請 人之敘述，下列何者正確？', '["收養及終止收養登記都必須由甲男與乙女二人共同申辦", "收養登記必須由甲乙二人共同申辦，終止收養登記由其中一人申辦即可", "收養登記可由甲乙二人中之一人申辦，終止收養登記必須由二人共同申辦", "收養及終止收養登記均可由甲乙二人中之一人申辦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
